<script lang="ts">
	import { onMount } from 'svelte';
	import { cubicOut } from 'svelte/easing';
	import { Tween } from 'svelte/motion';

	let { customClass = '' }: { customClass?: string } = $props();

	const INITIAL_NAMESPACE_WIDTH = 142;
	const FINAL_NAMESPACE_WIDTH = 640;

	const namespaceWidth = new Tween(INITIAL_NAMESPACE_WIDTH, { duration: 1000, easing: cubicOut });
	let scalingFactor = $derived(namespaceWidth.current / FINAL_NAMESPACE_WIDTH);
	let picture: HTMLElement;
	let hasStartedAnimation = false;

	const resourceOpacity = new Tween(0, { duration: 800, easing: cubicOut });

	onMount(() => {
		const handleScroll = () => {
			if (!picture || hasStartedAnimation) {
				return;
			}

			const threshold = window.innerHeight - 120;
			const pictureTop = picture.getBoundingClientRect().top;

			if (pictureTop <= threshold) {
				hasStartedAnimation = true;
				window.removeEventListener('scroll', handleScroll);

				const animation = namespaceWidth.set(FINAL_NAMESPACE_WIDTH);
				animation.then(() => {
					resourceOpacity.set(1);
				});
			}
		};
		// Set the initial state
		handleScroll();
		window.addEventListener('scroll', handleScroll, { passive: true });

		return () => {
			window.removeEventListener('scroll', handleScroll);
		};
	});
</script>

